// Limit to MAX_YEARS most recent CSVs (configurable). Older years can be backfilled
// later by raising this cap or by a one-off backfill workflow.
const MAX_YEARS = 3;

const pkg = $input.first().json.result || {};
const resources = pkg.resources || [];

function parseCsvLine(line) {
  const out = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (inQuotes) {
      if (c === '"') {
        if (line[i + 1] === '"') { cur += '"'; i++; }
        else { inQuotes = false; }
      } else cur += c;
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ',') { out.push(cur); cur = ''; }
      else cur += c;
    }
  }
  out.push(cur);
  return out;
}

function extractYear(url) {
  let m = url.match(/(20\d\d)/);
  if (m) return parseInt(m[1], 10);
  m = url.match(/cy(\d\d)/i);
  if (m) return 2000 + parseInt(m[1], 10);
  return null;
}

const targets = [];
for (const r of resources) {
  const url = (r && r.url) || '';
  if (!/\.csv(\?|$)/i.test(url)) continue;
  if (/payroll_categories/i.test(url)) continue;
  const year = extractYear(url);
  if (!year) continue;
  targets.push({ url, year, filename: url.split('/').pop() });
}
targets.sort((a, b) => b.year - a.year);
const limited = targets.slice(0, MAX_YEARS);

const out = [];
for (const t of limited) {
  const text = await this.helpers.httpRequest({ method: 'GET', url: t.url, encoding: 'utf8' });
  const lines = String(text).split(/\r?\n/);
  if (lines.length < 2) continue;
  const header = parseCsvLine(lines[0]).map(h => h.trim());

  // older CSVs use 'DEPARTMENT NAME', newer use 'DEPARTMENT_NAME'; etc.
  function findIdx(...candidates) {
    for (const c of candidates) {
      const i = header.indexOf(c);
      if (i >= 0) return i;
    }
    return -1;
  }
  const iName    = findIdx('NAME');
  const iDept    = findIdx('DEPARTMENT_NAME', 'DEPARTMENT NAME');
  const iTitle   = findIdx('TITLE');
  const iRegular = findIdx('REGULAR');
  const iRetro   = findIdx('RETRO');
  const iOther   = findIdx('OTHER');
  const iOT      = findIdx('OVERTIME');
  const iInjured = findIdx('INJURED');
  const iDetail  = findIdx('DETAIL');
  const iQuinn   = findIdx('QUINN_EDUCATION', 'QUINN/EDUCATION INCENTIVE', 'QUINN');
  const iTotal   = findIdx('TOTAL GROSS', 'TOTAL_EARNINGS', 'TOTAL EARNINGS', 'TOTAL_GROSS');
  const iPostal  = findIdx('POSTAL', 'ZIP', 'POSTAL_CODE');

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    if (!line || !line.trim()) continue;
    const f = parseCsvLine(line);
    const dept = (iDept >= 0 ? f[iDept] : '') || '';
    if (!/police department/i.test(dept)) continue;
    const cell = (k) => k >= 0 && f[k] != null ? String(f[k]).trim() || null : null;
    out.push({ json: {
      name: cell(iName),
      department_name: dept.trim(),
      title: cell(iTitle),
      regular: cell(iRegular),
      retro: cell(iRetro),
      other: cell(iOther),
      overtime: cell(iOT),
      injured: cell(iInjured),
      detail: cell(iDetail),
      quinn: cell(iQuinn),
      total_earnings: cell(iTotal),
      postal: cell(iPostal),
      year: t.year,
      source_filename: t.filename
    }});
  }
}
return out;
